// Helix Lamp — a warm glowing spiral coil is the hero. The coil is a genuine
// 3D helix built from overlapping capsule segments traced along a parametric
// helical path (x = R cosθ, y = R sinθ, z rising with θ). Each segment overlaps
// its neighbour so the smooth field welds into one continuous glowing tube.
// It stands on a darker metallic base and is capped by a warm lamp finial.
const { sdf } = api;

// ---- The helical coil (the hero) -------------------------------------------
const TURNS      = 4;          // number of full revolutions
const COIL_R     = 11;         // radius of the helix (how wide the spiral is)
const TUBE_R     = 2.6;        // radius of the glowing tube itself
const PITCH      = 8.5;        // vertical rise per full turn
const SEG_PER_T  = 24;         // segments per turn (overlap → smooth weld)
const Z0         = 2;          // bottom of the coil (sits just above the base)

const total = TURNS * SEG_PER_T;
function helixPt(i) {
  const t = i / SEG_PER_T;                 // turns elapsed
  const a = t * Math.PI * 2;
  return [COIL_R * Math.cos(a), COIL_R * Math.sin(a), Z0 + t * PITCH];
}

let coil = null;
for (let i = 0; i < total; i++) {
  const p0 = helixPt(i);
  const p1 = helixPt(i + 1);
  const seg = sdf.capsule(p0, p1, TUBE_R);
  coil = coil ? coil.union(seg) : seg;
}
// The coil is one continuous glowing element → one paint label.
coil = coil.label('coil');

const coilTopZ = Z0 + TURNS * PITCH;        // ≈ 36

// ---- A slender inner spine so the lamp reads as a column, not just a spring -
// A thin warm post up the centre of the spiral, smooth-welded to the coil at
// top and bottom so the whole thing is one watertight piece. Same 'coil' glow
// color (label propagates through translate; we union under one outer label).
const spine = sdf.cylinder(1.6, coilTopZ - Z0 + 2)
  .translate(0, 0, (Z0 + coilTopZ) / 2);

// ---- The lamp finial on top (warm glowing bulb) ----------------------------
const bulb = sdf.sphere(5).translate(0, 0, coilTopZ + 4)
  .smoothUnion(sdf.cylinder(2.2, 4).translate(0, 0, coilTopZ + 1), 1.2);

// Weld coil + spine + bulb into one warm 'coil' glow region. smoothUnion drops
// labels, so we label the whole warm assembly once on the outside.
const lamp = coil.union(spine).smoothUnion(bulb, 1.5).label('coil');

// ---- The base (dark metallic plinth) ---------------------------------------
// A rounded disc with a short collar the coil plugs into. Hard-union so its
// label survives partitioning and it paints a distinct metallic color.
const baseDisc   = sdf.roundedCylinder(14, 5, 1.4).translate(0, 0, -2.5);
const baseCollar = sdf.roundedCylinder(6, 4, 1.0).translate(0, 0, 1.5);
const base = baseDisc.smoothUnion(baseCollar, 1.8).label('base');

// ---- Compose ---------------------------------------------------------------
// Hard-union so 'coil' and 'base' stay separate paint regions. The base collar
// overlaps the coil bottom + spine so the whole model is one component.
return lamp.union(base).build({ edgeLength: 0.4 });

